request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?execName ?behaviorOrBlockType ?ifacePortName ?ifacePortType
WHERE {
  VALUES ?execNamePattern {
    "Procedure%20Executive%20and%20Analysis%20Software"
    "Procedure%20Executive%20and%20Analysis%20Software%20-%20PEAS"
    "Executive%20Software%20Behavior"
  }

  ?exec vocab:NamedElement_name ?execName .
  FILTER(
    ( CONTAINS(LCASE(STR(?execName)), LCASE("procedure executive and analysis software")) )
    ||
    ( CONTAINS(LCASE(STR(?execName)), LCASE("executive software behavior")) )
  )
  ?exec rdf:type ?behaviorOrBlockType .

  OPTIONAL {
    ?exec vocab:EncapsulatedClassifier_ownedPort ?port .
    ?port vocab:NamedElement_name ?ifacePortName .
    OPTIONAL { ?port rdf:type ?ifacePortType }
  }

  # If behavior/state machine, still try to surface event/action names
  OPTIONAL {
    ?exec vocab:Behavior_ownedBehavior ?subBeh .
    ?subBeh vocab:NamedElement_name ?ifacePortName .
  }
}
LIMIT 25
